import Head from "next/head";
import styles from "./index.module.css";

function HomePage() {
  return (
    <div className="container">
      <Head>
       <title>Home</title>
        <meta
          name="description"
          content="Kişisel web sitem"
        />
      </Head>
      <Navigation />
    </div>
  );
}

export default HomePage;
